import os
import io
import csv
import hashlib
import time
from pathlib import Path
from typing import List, Dict, Any
import numpy as np
import tensorflow as tf
from tensorflow import keras
from tensorflow.keras import layers
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import pandas as pd
from PIL import Image

app = Flask(__name__)

UPLOAD_FOLDER = 'uploads'
MODEL_FOLDER = 'models'
ALLOWED_EXTENSIONS = {'csv', 'png', 'jpg', 'jpeg'}
MAX_FILE_SIZE = 50 * 1024 * 1024

os.makedirs(UPLOAD_FOLDER, exist_ok=True)
os.makedirs(MODEL_FOLDER, exist_ok=True)

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_FILE_SIZE

training_data_store = []
image_data_store = []
model = None


def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS


def create_model(input_shape=(224, 224, 3), num_classes=10):
    model = keras.Sequential([
        layers.Conv2D(32, (3, 3), activation='relu', input_shape=input_shape),
        layers.MaxPooling2D((2, 2)),
        layers.Conv2D(64, (3, 3), activation='relu'),
        layers.MaxPooling2D((2, 2)),
        layers.Conv2D(128, (3, 3), activation='relu'),
        layers.MaxPooling2D((2, 2)),
        layers.Flatten(),
        layers.Dense(128, activation='relu'),
        layers.Dropout(0.5),
        layers.Dense(num_classes, activation='softmax')
    ])
    
    model.compile(
        optimizer='adam',
        loss='sparse_categorical_crossentropy',
        metrics=['accuracy']
    )
    
    return model


def preprocess_image(image_path, target_size=(224, 224)):
    img = Image.open(image_path).convert('RGB')
    img = img.resize(target_size)
    img_array = np.array(img) / 255.0
    return img_array


@app.route('/upload_csv', methods=['POST'])
def upload_csv():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        timestamp = str(int(time.time()))
        unique_filename = f"{timestamp}_{filename}"
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], unique_filename)
        file.save(filepath)
        
        try:
            df = pd.read_csv(filepath)
            data_dict = df.to_dict('records')
            training_data_store.extend(data_dict)
            
            return jsonify({
                'message': 'CSV uploaded successfully',
                'filename': unique_filename,
                'records_added': len(data_dict),
                'total_records': len(training_data_store)
            }), 200
        except Exception as e:
            return jsonify({'error': f'Error processing CSV: {str(e)}'}), 500
    
    return jsonify({'error': 'Invalid file type'}), 400


@app.route('/upload_image', methods=['POST'])
def upload_image():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    label = request.form.get('label', '0')
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        timestamp = str(int(time.time()))
        file_hash = hashlib.md5(file.read()).hexdigest()
        file.seek(0)
        unique_filename = f"{timestamp}_{file_hash}_{filename}"
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], unique_filename)
        file.save(filepath)
        
        try:
            img_array = preprocess_image(filepath)
            image_data_store.append({
                'filepath': filepath,
                'label': int(label),
                'data': img_array
            })
            
            return jsonify({
                'message': 'Image uploaded successfully',
                'filename': unique_filename,
                'label': label,
                'total_images': len(image_data_store)
            }), 200
        except Exception as e:
            return jsonify({'error': f'Error processing image: {str(e)}'}), 500
    
    return jsonify({'error': 'Invalid file type'}), 400


@app.route('/contribute_batch', methods=['POST'])
def contribute_batch():
    if 'files[]' not in request.files:
        return jsonify({'error': 'No files provided'}), 400
    
    files = request.files.getlist('files[]')
    labels = request.form.getlist('labels[]')
    
    if len(files) != len(labels):
        return jsonify({'error': 'Number of files and labels must match'}), 400
    
    uploaded_files = []
    errors = []
    
    for idx, file in enumerate(files):
        if file and allowed_file(file.filename):
            filename = secure_filename(file.filename)
            timestamp = str(int(time.time()))
            unique_filename = f"{timestamp}_{idx}_{filename}"
            filepath = os.path.join(app.config['UPLOAD_FOLDER'], unique_filename)
            
            try:
                file.save(filepath)
                img_array = preprocess_image(filepath)
                image_data_store.append({
                    'filepath': filepath,
                    'label': int(labels[idx]),
                    'data': img_array
                })
                uploaded_files.append(unique_filename)
            except Exception as e:
                errors.append(f"Error processing {filename}: {str(e)}")
    
    return jsonify({
        'message': 'Batch upload completed',
        'uploaded': len(uploaded_files),
        'errors': errors,
        'total_images': len(image_data_store)
    }), 200


@app.route('/train', methods=['POST'])
def train_model():
    global model
    
    if len(image_data_store) < 10:
        return jsonify({'error': 'Insufficient training data. Need at least 10 images'}), 400
    
    params = request.json or {}
    epochs = params.get('epochs', 10)
    batch_size = params.get('batch_size', 32)
    
    try:
        X_train = np.array([item['data'] for item in image_data_store])
        y_train = np.array([item['label'] for item in image_data_store])
        
        num_classes = len(np.unique(y_train))
        
        if model is None:
            model = create_model(input_shape=X_train.shape[1:], num_classes=num_classes)
        
        history = model.fit(
            X_train, y_train,
            epochs=epochs,
            batch_size=batch_size,
            validation_split=0.2,
            verbose=0
        )
        
        model_path = os.path.join(MODEL_FOLDER, f'model_{int(time.time())}.h5')
        model.save(model_path)
        
        return jsonify({
            'message': 'Model trained successfully',
            'model_path': model_path,
            'training_samples': len(X_train),
            'num_classes': num_classes,
            'final_accuracy': float(history.history['accuracy'][-1]),
            'final_val_accuracy': float(history.history['val_accuracy'][-1]) if 'val_accuracy' in history.history else None,
            'epochs': epochs
        }), 200
    except Exception as e:
        return jsonify({'error': f'Training error: {str(e)}'}), 500


@app.route('/predict', methods=['POST'])
def predict():
    global model
    
    if model is None:
        return jsonify({'error': 'Model not trained yet'}), 400
    
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], f"temp_{filename}")
        file.save(filepath)
        
        try:
            img_array = preprocess_image(filepath)
            img_array = np.expand_dims(img_array, axis=0)
            
            predictions = model.predict(img_array)
            predicted_class = int(np.argmax(predictions[0]))
            confidence = float(np.max(predictions[0]))
            
            os.remove(filepath)
            
            return jsonify({
                'predicted_class': predicted_class,
                'confidence': confidence,
                'all_probabilities': predictions[0].tolist()
            }), 200
        except Exception as e:
            if os.path.exists(filepath):
                os.remove(filepath)
            return jsonify({'error': f'Prediction error: {str(e)}'}), 500
    
    return jsonify({'error': 'Invalid file type'}), 400


@app.route('/stats', methods=['GET'])
def get_stats():
    return jsonify({
        'total_csv_records': len(training_data_store),
        'total_images': len(image_data_store),
        'model_trained': model is not None,
        'classes': list(set([item['label'] for item in image_data_store])) if image_data_store else []
    }), 200


@app.route('/load_model', methods=['POST'])
def load_model():
    global model
    
    params = request.json or {}
    model_path = params.get('model_path')
    
    if not model_path or not os.path.exists(model_path):
        return jsonify({'error': 'Invalid model path'}), 400
    
    try:
        model = keras.models.load_model(model_path)
        return jsonify({'message': 'Model loaded successfully'}), 200
    except Exception as e:
        return jsonify({'error': f'Error loading model: {str(e)}'}), 500


@app.route('/reset', methods=['POST'])
def reset_data():
    global model, training_data_store, image_data_store
    
    training_data_store = []
    image_data_store = []
    model = None
    
    return jsonify({'message': 'All data reset successfully'}), 200


if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)